// Build the cold email (language-aware: EN or RO)
const job = $input.first().json;
const lead = job.lead;
const result = job.result;
const lang = lead.language || 'en';
const isRo = lang === 'ro';
const scores = result.scores;
const issues = result.top_issues.slice(0, 3);
const opportunity = result.summary.opportunity || '';
const subject = isRo
  ? result.email_ready.subject.ro
  : result.email_ready.subject.en;

const issues_html = issues.map(i =>
  `<li style="margin-bottom:6px;color:#334155;">${i.title}</li>`
).join('');

let html;
if (isRo) {
  html = `
<div style="font-family:Inter,sans-serif;max-width:600px;margin:0 auto;padding:0;color:#1e293b;">
  <p>Bun\u0103 ziua <strong>${lead.first_name}</strong>,</p>

  <p>Am analizat website-ul <strong>${lead.company_name}</strong> din perspectiva vizibilit\u0103\u021bii \u00een motoarele de c\u0103utare AI (ChatGPT, Google AI Overviews, Perplexity) \u015fi am creat un raport gratuit:</p>

  <p style="margin:20px 0;">
    <a href="${job.report_url}" style="background:#4f46e5;color:white;padding:12px 24px;border-radius:8px;text-decoration:none;font-weight:600;display:inline-block;">
      &#x2192; Vezi raportul complet
    </a>
  </p>

  <p><strong>Scor GEO curent: ${scores.geo_score}/100</strong> (media industriei: 61/100)</p>
  <p style="color:#16a34a;"><em>${opportunity}</em></p>

  <p><strong>Principalele probleme identificate:</strong></p>
  <ul style="padding-left:20px;">${issues_html}</ul>

  <p>Dac\u0103 e\u015fti interesat de o consulta\u021bie gratuit\u0103 de 20 de minute \u00een care discut\u0103m cum putem rezolva aceste probleme, r\u0103spunde la acest email.</p>

  <br>
  <p>Cu respect,<br>
  <strong>Cosmin Stan</strong><br>
  <a href="https://nrankai.com" style="color:#4f46e5;">nrankai.com</a> | hello@nrankai.com</p>

  <p style="color:#94a3b8;font-size:11px;border-top:1px solid #e2e8f0;padding-top:12px;margin-top:24px;">
    Ai primit acest email deoarece website-ul t\u0103u a fost inclus \u00eentr-o analiz\u0103 gratuit\u0103 de vizibilitate AI.
    Dac\u0103 nu e\u015fti interesat, ignor\u0103 acest email.
  </p>
</div>`;
} else {
  html = `
<div style="font-family:Inter,sans-serif;max-width:600px;margin:0 auto;padding:0;color:#1e293b;">
  <p>Hi <strong>${lead.first_name}</strong>,</p>

  <p>I ran a free GEO visibility audit on <strong>${lead.company_name}</strong>'s website &#x2014; checking how well it appears in AI search engines (ChatGPT, Google AI Overviews, Perplexity):</p>

  <p style="margin:20px 0;">
    <a href="${job.report_url}" style="background:#4f46e5;color:white;padding:12px 24px;border-radius:8px;text-decoration:none;font-weight:600;display:inline-block;">
      &#x2192; View Your Free Report
    </a>
  </p>

  <p><strong>Current GEO Score: ${scores.geo_score}/100</strong> (industry average: 61/100)</p>
  <p style="color:#16a34a;"><em>${opportunity}</em></p>

  <p><strong>Top issues found:</strong></p>
  <ul style="padding-left:20px;">${issues_html}</ul>

  <p>If you'd like a free 20-minute call to walk through these findings and discuss next steps, just reply to this email.</p>

  <br>
  <p>Best,<br>
  <strong>Cosmin Stan</strong><br>
  <a href="https://nrankai.com" style="color:#4f46e5;">nrankai.com</a> | hello@nrankai.com</p>

  <p style="color:#94a3b8;font-size:11px;border-top:1px solid #e2e8f0;padding-top:12px;margin-top:24px;">
    You received this because your website was included in a free AI visibility analysis.
    Not interested? Simply ignore this email.
  </p>
</div>`;
}

return [{ json: {
  to: lead.email,
  subject,
  html,
  first_name: lead.first_name,
  company: lead.company_name,
  job_id: job.job_id
}}];
